gsap.registerPlugin(ScrollTrigger);

// ── Locomotive Scroll REMOVED — using native scroll ──────────────────────────
// ScrollTrigger works with native scroll by default (no scroller proxy needed)

// ── Hero video: paused, plays ONCE on scroll ─────────────────────────────────
const heroVideo = document.querySelector("#hero-video");
if (heroVideo) {
  heroVideo.pause();
      let played = false;
            ScrollTrigger.create({
                      trigger: "#pages-overlay", start: "top 90%",
                                    onEnter: () => { if (!played) { played = true; heroVideo.play(); } },
                                                      onLeave: () => heroVideo.pause()
                                                                          });
                                                                                              }

                                                                                                                  // ── page-bottom text fades as you start scrolling ───────────────────────────
                                                                                                                                      gsap.to("#page-bottom", {
                                                                                                                                                            scrollTrigger: { trigger: "#pages-overlay", start: "top 80%", end: "top 30%", scrub: .5 },
                                                                                                                                                                                    opacity: 0
                                                                                                                                                                                                            });

                                                                                                                                                                                                                                    // ── Slide-up headings (page1, page2, page4) ──────────────────────────────────
                                                                                                                                                                                                                                                            const slideUp = (page, el) =>
                                                                                                                                                                                                                                                                                      gsap.timeline({ scrollTrigger: { trigger: page, start: "top top", scrub: 1, pin: true } })
                                                                                                                                                                                                                                                                                                                    .to(el, { top: "-50%" });
                                                                                                                                                                                                                                                                                                                                                  slideUp("#page1", "#page1>h1");
                                                                                                                                                                                                                                                                                                                                                                                slideUp("#page2", "#page2>h1");
                                                                                                                                                                                                                                                                                                                                                                                                              slideUp("#page4", "#page4>#center-page4");

                                                                                                                                                                                                                                                                                                                                                                                                                                            // ── Canvas 360° spin (page7) — 199 frames-by dev.shahid  ────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          function makeCanvas(selector, urls, pinTrigger, end, scaleMode) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const canvas = document.querySelector(selector);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (!canvas) return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const ctx = canvas.getContext("2d");
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              resize();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        window.addEventListener("resize", () => { resize(); render(); });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const images = urls.map(src => { const img = new Image(); img.src = src; return img; });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const seq = { frame: 0 };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  function render() {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const img = images[seq.frame];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (!img || !img.complete || !img.naturalWidth) return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const hr = canvas.width / img.width, vr = canvas.height / img.height;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const r = scaleMode === "max" ? Math.max(hr, vr) : Math.min(hr, vr);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const cx = (canvas.width - img.width * r) / 2, cy = (canvas.height - img.height * r) / 2;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ctx.clearRect(0, 0, canvas.width, canvas.height);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ctx.drawImage(img, 0, 0, img.width, img.height, cx, cy, img.width * r, img.height * r);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                images[0].onload = render;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  gsap.to(seq, {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        frame: images.length - 1, snap: "frame", ease: "none",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  scrollTrigger: { scrub: .15, trigger: selector, start: "top top", end },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onUpdate: render
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ScrollTrigger.create({ trigger: pinTrigger, pin: true, start: "top top", end });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      const BASE = "https://www.apple.com/105/media/us/apple-vision-pro/2023/7e268c13-eb22-493d-a860-f0637bacb569/anim/360/large/";
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        makeCanvas(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "#page8>canvas",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  Array.from({ length: 200 }, (_, i) => BASE + String(i).padStart(4, "0") + ".jpg"),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          "#page8>canvas", "500% top", "min"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          